import {
  getAllPosts,
  getAllPages,
  getAllCategories,
  getAllMedia,
  getAnalytics,
  createPost,
  updatePost,
  deletePost,
  createPage,
  updatePage,
  deletePage,
  createCategory,
  updateCategory,
  deleteCategory,
  deleteMedia,
  type LocalPost,
  type LocalPage,
  type LocalCategory,
  type LocalMedia,
} from './local-data';

// Re-export all functions for backward compatibility
export {
  getAllPosts,
  getAllPages,
  getAllCategories,
  getAllMedia,
  getAnalytics,
  createPost,
  updatePost,
  deletePost,
  createPage,
  updatePage,
  deletePage,
  createCategory,
  updateCategory,
  deleteCategory,
  deleteMedia,
};

// Export types
export type {
  LocalPost as Post,
  LocalPage as Page,
  LocalCategory as Category,
  LocalMedia as Media,
};

// Additional helper functions for admin dashboard
export function getPostsByStatus(status: LocalPost['status']) {
  return getAllPosts().filter(post => post.status === status);
}

export function getPagesByStatus(status: LocalPage['status']) {
  return getAllPages().filter(page => page.status === status);
}

export function searchPosts(query: string) {
  const posts = getAllPosts();
  return posts.filter(post => 
    post.title.toLowerCase().includes(query.toLowerCase()) ||
    post.content.toLowerCase().includes(query.toLowerCase()) ||
    post.excerpt.toLowerCase().includes(query.toLowerCase())
  );
}

export function searchPages(query: string) {
  const pages = getAllPages();
  return pages.filter(page => 
    page.title.toLowerCase().includes(query.toLowerCase()) ||
    page.content.toLowerCase().includes(query.toLowerCase()) ||
    page.excerpt.toLowerCase().includes(query.toLowerCase())
  );
}

export function getRecentPosts(limit = 10) {
  return getAllPosts()
    .sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
    .slice(0, limit);
}

export function getRecentPages(limit = 10) {
  return getAllPages()
    .sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
    .slice(0, limit);
}

export function getPostsByCategory(categorySlug: string) {
  const posts = getAllPosts();
  return posts.filter(post => post.categories.includes(categorySlug));
}

export function duplicatePost(id: string) {
  const originalPost = getAllPosts().find(post => post.id === id);
  if (!originalPost) return undefined;

  const duplicatedPost = createPost({
    ...originalPost,
    title: `${originalPost.title} (Copy)`,
    slug: `${originalPost.slug}-copy`,
    status: 'draft',
  });

  return duplicatedPost;
}

export function duplicatePage(id: string) {
  const originalPage = getAllPages().find(page => page.id === id);
  if (!originalPage) return undefined;

  const duplicatedPage = createPage({
    ...originalPage,
    title: `${originalPage.title} (Copy)`,
    slug: `${originalPage.slug}-copy`,
    status: 'draft',
  });

  return duplicatedPage;
}
