import { writeFileSync, readFileSync, existsSync, mkdirSync } from 'fs';
import { join } from 'path';

// Types for local content management
export interface LocalPost {
  id: string;
  title: string;
  slug: string;
  content: string;
  excerpt: string;
  status: 'draft' | 'publish' | 'private' | 'trash';
  author: string;
  createdAt: string;
  updatedAt: string;
  categories: string[];
  tags: string[];
  featuredImage?: string;
  meta?: {
    description?: string;
    keywords?: string[];
  };
}

export interface LocalPage {
  id: string;
  title: string;
  slug: string;
  content: string;
  excerpt: string;
  status: 'draft' | 'publish' | 'private' | 'trash';
  author: string;
  createdAt: string;
  updatedAt: string;
  template?: string;
  meta?: {
    description?: string;
    keywords?: string[];
  };
}

export interface LocalCategory {
  id: string;
  name: string;
  slug: string;
  description: string;
  parent?: string;
  createdAt: string;
  updatedAt: string;
}

export interface LocalMedia {
  id: string;
  filename: string;
  originalName: string;
  mimeType: string;
  size: number;
  url: string;
  altText?: string;
  caption?: string;
  uploadedAt: string;
}

// Data storage paths
const DATA_DIR = join(process.cwd(), 'data');
const POSTS_FILE = join(DATA_DIR, 'posts.json');
const PAGES_FILE = join(DATA_DIR, 'pages.json');
const CATEGORIES_FILE = join(DATA_DIR, 'categories.json');
const MEDIA_FILE = join(DATA_DIR, 'media.json');

// Ensure data directory exists
function ensureDataDir() {
  if (!existsSync(DATA_DIR)) {
    mkdirSync(DATA_DIR, { recursive: true });
  }
}

// Generic file operations
function readData<T>(filePath: string, defaultValue: T[]): T[] {
  ensureDataDir();
  try {
    if (existsSync(filePath)) {
      const data = readFileSync(filePath, 'utf-8');
      return JSON.parse(data);
    }
  } catch (error) {
    console.error(`Error reading ${filePath}:`, error);
  }
  return defaultValue;
}

function writeData<T>(filePath: string, data: T[]): void {
  ensureDataDir();
  try {
    writeFileSync(filePath, JSON.stringify(data, null, 2));
  } catch (error) {
    console.error(`Error writing ${filePath}:`, error);
    throw error;
  }
}

// Posts management
export function getAllPosts(): LocalPost[] {
  return readData<LocalPost>(POSTS_FILE, []);
}

export function getPostById(id: string): LocalPost | undefined {
  const posts = getAllPosts();
  return posts.find(post => post.id === id);
}

export function getPostBySlug(slug: string): LocalPost | undefined {
  const posts = getAllPosts();
  return posts.find(post => post.slug === slug);
}

export function createPost(postData: Omit<LocalPost, 'id' | 'createdAt' | 'updatedAt'>): LocalPost {
  const posts = getAllPosts();
  const newPost: LocalPost = {
    ...postData,
    id: Date.now().toString(),
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
  
  posts.push(newPost);
  writeData(POSTS_FILE, posts);
  return newPost;
}

export function updatePost(id: string, updates: Partial<LocalPost>): LocalPost | undefined {
  const posts = getAllPosts();
  const index = posts.findIndex(post => post.id === id);
  
  if (index === -1) return undefined;
  
  posts[index] = {
    ...posts[index],
    ...updates,
    updatedAt: new Date().toISOString(),
  };
  
  writeData(POSTS_FILE, posts);
  return posts[index];
}

export function deletePost(id: string): boolean {
  const posts = getAllPosts();
  const filteredPosts = posts.filter(post => post.id !== id);
  
  if (filteredPosts.length === posts.length) return false;
  
  writeData(POSTS_FILE, filteredPosts);
  return true;
}

